27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	const HIGH_ENCHANTMENT_THRESHOLD = 5;
33	const LOYALTY_DISCOUNT_RATE = 0.2;
34	const LOYALTY_YEARS_THRESHOLD = 2;
35	
36	const BASE_PREMIUM: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
44	
45	const COMPONENT_TYPES = ["rune", "moonstone"];
46	
47	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
48	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
49	
50	const countItemsOfType = (items: Item[], type: string): number =>
51	  items.filter((item) => item.type === type).length;
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	const isHighlyEnchanted = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
56	
57	const ITEM_SURCHARGE_RATES: ReadonlyArray<{
58	  applies: (item: Item) => boolean;
59	  rate: number;
60	}> = [
61	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
62	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
63	];
64	
65	const surchargesForItem = (item: Item): number => {
66	  const base = BASE_PREMIUM[item.type];
67	  return ITEM_SURCHARGE_RATES.reduce(
68	    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
69	    0,
70	  );
71	};
72	
73	const sumItemSpecificSurcharges = (items: Item[]): number =>
74	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
75	
76	const calculateBasePremium = (items: Item[]): number => {
77	  const subtotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
78	  const totalDiscount = COMPONENT_TYPES.reduce(
79	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
80	    0,
81	  );
82	  return subtotal - totalDiscount;
83	};
84	
85	const loyaltyDiscount = (basePremium: number, customer: Scenario["customer"]): number =>
86	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
87	
88	const quote = (step: QuoteStep, customer: Scenario["customer"]): QuoteResult => {
89	  const basePremium = calculateBasePremium(step.items);
90	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
91	  const firstContractSurcharge = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
92	  const premium = Math.ceil(
93	    basePremium +
94	      itemSurcharges +
95	      firstContractSurcharge -
96	      loyaltyDiscount(basePremium, customer) +
97	      PROCESSING_FEE,
98	  );
99	  return { premium };
100	};
101	
102	export const runScenario = (scenario: Scenario): ScenarioResult => {
103	  const results = scenario.steps.map((step) => quote(step, scenario.customer));
104	  return { results };
105	};
